import axios from 'axios';
import React, { useEffect, useState } from 'react';
import { Select, Option,Input } from "@material-tailwind/react";
import { useNavigate } from 'react-router-dom';

export default function AddGroup() {

  const [group_number,setGroup_number ] = useState()
  const [kurs,setKurs ] = useState()
  const [speciality,setSpeciality ] = useState()

  const navigate = useNavigate()

  const Submi = (e)=>{
    e.preventDefault();
    axios.post("http://localhost:5555/groups",{group_number,kurs,speciality})
    .then(result=>{console.log(result)
      navigate('/')
    })
    .catch(err=>console.log(err))
  }

  const [specialities, setSpecialities] = useState([])
  useEffect(()=>{
    axios.get("http://localhost:5555/specialities")
    .then(specialities=>setSpecialities(specialities.data))
    .catch(err=>console.log(err))
  },[])

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <div className="flex justify-end">
      <button size="sm" class="bg-blue-500 text-white px-4 py-2 rounded-md justify-end">
      Add
      </button>
      </div>
      <strong className="text-gray-700 font-medium">Groups</strong>
      <form>      
        <div className="border-x border-gray-200 rounded-sm mt-2">
        <table className="table-auto text-gray-700">
          <thead>
            <tr>
              <th>Специальност</th>
              <th>Курс</th>
              <th>Группа</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>
              <Select>
                  {specialities.map(item => (
                <Option key={item._id} onChange={(e)=>setSpecialities}>{item.speciality}</Option>))}
              </Select>
              </td>
              <td>
              <Select onChange={(e)=>setKurs}>
                <Option>1</Option>
                <Option>2</Option>
                <Option>3</Option>
                <Option>4</Option>
              </Select>
              </td>
              <td>
              <Input onChange={(e)=>setGroup_number}/>
              </td>
            </tr>  


          </tbody>
        </table>
      </div></form>

    </div>
  );
};
